--- /dev/null
+++ b/Sources/Networking/RetryPolicy.swift
@@ -0,0 +1,30 @@
+import Foundation
+
+struct RetryPolicy {
+    let maxRetries: Int
+    let backoffMultiplier: Double
+
+    func shouldRetry(attempt: Int, error: Error) -> Bool {
+        attempt < maxRetries
+    }
+
+    func delay(for attempt: Int) -> TimeInterval {
+        pow(backoffMultiplier, Double(attempt))
+    }
+}
